prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?modelName
  ?model
  (COUNT(DISTINCT ?task) AS ?customerTaskCount)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  ?task bboExt:initiatingParticipantRef ?partRef .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .

  FILTER(
    STRENDS(STR(?participant), ?partRef) &&
    CONTAINS(LCASE(STR(?participantName)), "customer")
  )
}
GROUP BY ?modelName ?model
ORDER BY ASC(?customerTaskCount)
LIMIT 1

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?modelName
  ?taskCount
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  {
    SELECT ?modelName (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
      ?choreo tai:belongsTo ?model .
    }
    GROUP BY ?modelName
  }
  FILTER(?taskCount > 0)
}
ORDER BY ?taskCount
LIMIT 25

